external_knowledge:
- Highly stressed patients refer to those with a stress level greater than 3; 
- Body mass index groups are formed by rounding up the BMI values;
- Chronic kidney disease patients are identified based on their condition name in the chronic conditions table.

- 'significant health issues' refers to severe chronic conditions;
- 'concluded their treatment' implies that the status of the treatment plan is 'Completed';
- 'multiple' here means more than two severe chronic conditions;

sql:
SELECT AVG(salt_content_in_diet) AS average_salt_content
FROM patients
WHERE pregnancy_status = 'Y' AND level_of_stress > 3;

external_knowledge:
- 'stormy waves' refers to the average systolic blood pressure; 
- 'calm depths' refers to the average diastolic blood pressure;
- 'turbulent tides' refers to the average stress level;
- 'navigating the rough seas of chronic kidney disease' means patients with chronic kidney disease (chronic_kidney_disease = 'Y').

sql:
SELECT COUNT(DISTINCT cc.patient_id) AS patient_count
FROM chronic_conditions cc
WHERE cc.condition_name = 'Diabetes';

SELECT AVG(salt_content_in_diet) AS average_salt_content
FROM patients
WHERE chronic_kidney_disease = 'Y' AND adrenal_and_thyroid_disorders = 'Y';

SELECT patient_id, AVG(systolic_bp) AS average_systolic_bp
FROM blood_pressure
GROUP BY patient_id;

SELECT AVG(BMI) AS average_bmi
FROM patients
WHERE smoking_status = 'Y' AND pregnancy_status = 'N';
